 1	import { type FC, type Ref, useState } from 'react';
 2	
 3	import {
 4	  Dropdown,
 5	  DropdownItem,
 6	  DropdownList,
 7	  MenuToggle,
 8	  type MenuToggleElement,
 9	} from '@patternfly/react-core';
10	import { EllipsisVIcon } from '@patternfly/react-icons';
11	import { useForkliftTranslation } from '@utils/i18n';
12	
13	import type { AffinityRowData } from './utils/types';
14	
15	import './AffinityRowActionsDropdown.scss';
16	
17	type AffinityRowActionsDropdownProps = {
18	  affinity: AffinityRowData;
19	  onDelete: (affinity: AffinityRowData) => void;
20	  onEdit: (affinity: AffinityRowData) => void;
21	};
22	
23	const AffinityRowActionsDropdown: FC<AffinityRowActionsDropdownProps> = ({
24	  affinity,
25	  onDelete,
26	  onEdit,
27	}) => {
28	  const { t } = useForkliftTranslation();
29	
30	  const [isOpen, setIsOpen] = useState(false);
31	
32	  const onToggleClick = () => {
33	    setIsOpen((prevIsOpen) => !prevIsOpen);
34	  };
35	
36	  const onSelect = () => {
37	    setIsOpen(false);
38	  };
39	
40	  const handleDelete = () => {
41	    onDelete(affinity);
42	    setIsOpen(false);
43	  };
44	  return (
45	    <Dropdown
46	      className="forklift-dropdown"
47	      isOpen={isOpen}
48	      onOpenChange={setIsOpen}
49	      onSelect={onSelect}
50	      toggle={(toggleRef: Ref<MenuToggleElement>) => (
51	        <MenuToggle ref={toggleRef} onClick={onToggleClick} isExpanded={isOpen} variant="plain">
52	          <EllipsisVIcon />
53	        </MenuToggle>
54	      )}
55	      shouldFocusToggleOnSelect
56	      popperProps={{
57	        position: 'right',
58	        width: '200px',
59	      }}
60	    >
61	      <DropdownList>
62	        <DropdownItem
63	          key="edit"
64	          onClick={() => {
65	            onEdit(affinity);
66	          }}
67	        >
68	          {t('Edit')}
69	        </DropdownItem>
70	        <DropdownItem key="delete" onClick={handleDelete}>
71	          {t('Delete')}
72	        </DropdownItem>
73	      </DropdownList>
74	    </Dropdown>
75	  );
76	};
77	
78	export default AffinityRowActionsDropdown;

